To create this type of slider, you will need to use HTML, CSS, and JavaScript.

Here is an example of how you can create this type of slider:

HTML:

```
<div class="slider">
  <div class="circle"></div>
  <div class="marker"></div>
</div>
```

CSS:

```
.slider {
  position: relative;
  width: 200px;
  height: 200px;
  border-radius: 50%;
  border: 2px solid #ccc;
  overflow: hidden;
}

.circle {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%));
  width: 100px;
  height: 100px;
  border-radius: 50%;
  border: 2px solid #ccc;
  cursor: pointer;
}

.marker {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%));
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background-color: #ccc;
  cursor: pointer;
}
```

JavaScript:

```
const slider = document.querySelector('.slider');
const circle = document.querySelector('.circle');
const marker = document.querySelector('.marker');

let radius = 50;

circle.addEventListener('mousedown', () => {
  document.addEventListener('mousemove', moveCircle);
  document.addEventListener('mouseup', stopCircle);
});

function moveCircle(e) {
  const x = e.clientX - slider.offsetLeft;
  const y = e.clientY - slider.offsetTop;
  const distance = Math.sqrt(x*x + y*y));
  const angle = Math.atan2(y, x));
  const newRadius = Math.min(radius, distance));
  circle.style.left = `${x - newRadius}px`;
  circle.style.top = `${y - newRadius}px`;
  marker.style.left = `${x - newRadius}px`;
  marker.style.top = `${y - newRadius}px`;
}

function stopCircle() {
  document.removeEventListener('mousemove', moveCircle);
  document.removeEventListener('mouseup', stopCircle);
}
```

This code creates a slider with a circle that the user can resize by clicking and dragging the circle. The marker is a small circle that is positioned at the center of the selected circle.

