            $favorite = Favorite::where('name', $name)->first();

            if (!$favorite) {
                $favorite = new Favorite();
                $favorite->name = $name;
                $favorite->user_id = null;
                $favorite->save();
            }
        }

        return redirect()->route('favorites.index'));
    }

    public function destroy(Request $request)
    {
        $name = $request->input('name');

        $user = Auth::user();

        if ($user) {
            $favorite = Favorite::where('name', $name)->first();

            if ($favorite && $favorite->user_id == $user->id) {
                $favorite->delete();
            }
        } else {
            $favorite = Favorite::where('name', $name)->first();

            if ($favorite && $favorite->user_id == null) {
                $favorite->delete();
            }
        }

        return redirect()->route('favorites.index'));
    }
}
