```
class rnn {
  private weights: number[][];
  private biases: number[];

  constructor(input_size: number, hidden_size: number) {
    this.weights = [
      new array(hidden_size).fill(0.1),
      new array(input_size).fill(0.1)
    ];
    this.biases = new array(hidden_size).fill(0.1);
  }

  public forward(input: number[]): number[] {
    const hidden = this.weights[0].map((w, i) => {
      return input.reduce((sum, x, j) => {
        return sum + x * this.weights[1][j] * this.weights[0][i][j];
      }, 0) + this.biases[i];
    });
    return hidden;
  }
}
```

