  function search(obj, path) {
    // If the current object is an array, loop through its elements
    if (Array.isArray(obj)) {
      for (let I = 0; I < obj.length; i++) {
        search(obj[i], path.concat(i));
      }
    }
    // If the current object is an object, loop through its properties
    else if (typeof obj === 'object') {
      for (let prop in obj) {
        if (obj.hasOwnProperty(prop)) {
          search(obj[prop], path.concat(prop)));
