Here's an example C# program that sends a POST request with a client certificate attached:

```
using System;
using System.Net;
using System.Security.Cryptography.X509Certificates;

class Program
{
    static void Main(string[] args)
    {
        // Set up the client certificate
        X509Certificate2 clientCert = new X509Certificate2("path/to/client/cert.pfx", "password");

        // Set up the request
        HttpWebRequest request = (HttpWebRequest)WebRequest.Create("https://example.com/api");
        request.Method = "POST";
        request.ContentType = "application/json";
        request.ClientCertificates.Add(clientCert);

        // Set up the request body
        string requestBody = "{\"name\":\"John\",\"age\":30}";
        byte[] requestBytes = System.Text.Encoding.UTF8.GetBytes(requestBody);
        request.ContentLength = requestBytes.Length;
        Stream requestStream = request.GetRequestStream();
        requestStream.Write(requestBytes, 0, requestBytes.Length);
        requestStream.Close();

        // Send the request and get the response
        HttpWebResponse response = (HttpWebResponse)request.GetResponse();
        Stream responseStream = response.GetResponseStream();
        byte[] responseBytes = new byte[response.ContentLength];
        responseStream.Read(responseBytes, 0, responseBytes.Length);
        responseStream.Close();
        response.Close();

        // Print the response
        string responseString = System.Text.Encoding.UTF8.GetString(responseBytes);
        Console.WriteLine(responseString);
    }
}
```

This program sets up a client certificate, sends a POST request with the certificate attached, and prints the response.

